public static void rotateArray(int[][] arr) {
    int n = arr.length;
    for (int layer = 0; layer < n / 2; layer++) {
        int first = layer;
        int last = n - layer - 1;
        for (int i = first; i < last; i++) {
            int offset = i - first;
            int newFirst = last - offset;
            int newLast = first + offset + 1;
            swap(arr, first, newFirst, newLast);
        }
    }
}

